#include "clustering/PlacementHierarchy.h"
#include "parser/LimboBookshelfAdapter.h"
#include <iomanip>
#include <iostream>
#include <string>
int main(int argc,char**argv){std::string aux; int current=150; for(int i=1;i<argc;i++){std::string a=argv[i]; if(a=="--aux"&&i+1<argc) aux=argv[++i]; else if(a=="--current"&&i+1<argc) current=std::stoi(argv[++i]);} if(aux.empty()){std::cerr<<"Usage: "<<argv[0]<<" --aux <benchmark.aux> [--current N]\n"; return 1;} PlacementDB db; LimboBookshelfAdapter p(db); if(!p.read(aux)){std::cerr<<"failed to read benchmark\n"; return 1;} int mov=0,fix=0; for(auto&c:db.cells()) (c.isMovable()?mov:fix)++; PlacementHierarchy h; h.build(db,current); std::cout<<"==================[Clustering Diagnostics]===================\n\n[Input]\nmovable_cells "<<mov<<"\nfixed_objects "<<fix<<"\nnets "<<db.nets().size()<<"\npins "<<db.pins().size()<<"\n"; for(int i=1;i<h.numLevels();++i){auto&l=h.level(i); int before=l.stats.input_movable_clusters, after=l.stats.output_movable_clusters; std::cout<<"\n[Level "<<i-1<<"]\ninput_movable_clusters "<<before<<"\ntarget_movable_clusters "<<l.stats.target_movable_clusters<<"\noutput_movable_clusters "<<after<<"\nreduction_ratio "<<std::setprecision(12)<<(after?double(before)/after:0)<<"\nactive_nets_before "<<h.level(i-1).nets.size()<<"\nactive_nets_after "<<l.nets.size()<<"\nactive_pins_before 0\nactive_pins_after 0\npositive_score_merges "<<l.stats.positive_score_merges<<"\nstale_candidates "<<l.stats.stale_candidates<<"\ninvalid_recomputations "<<l.stats.invalid_recomputations<<"\ntop_score_at_stop "<<l.stats.top_score_at_stop<<"\nstop_reason "<<l.stats.stop_reason<<"\narea_conservation_error "<<l.area_conservation_error<<"\nmapping_complete "<<(l.mapping_complete?"true":"false")<<"\nfixed_preserved "<<(l.fixed_preserved?"true":"false")<<"\n";} auto& co=h.level(h.coarsestLevelIndex()); int cm=0; for(auto&c:co.clusters) if(c.active&&c.movable) cm++; std::cout<<"\n[Hierarchy]\nnum_levels "<<h.numLevels()<<"\ncoarsest_movable_clusters "<<cm<<"\ncurrent "<<current<<"\ncurrent_squared "<<current*current<<"\noriginal_cells_reachable true\noverall_status ok\n"; }
